    64→func GetInstance(ds model.DataStore, playlists core.Playlists, cacheWarmer artwork.CacheWarmer, broker events.Broker) Scanner {
    65→	return singleton.GetInstance(func() *scanner {
    66→		s := &scanner{
    67→			ds:          ds,
    68→			pls:         playlists,
    69→			broker:      broker,
    70→			folders:     map[string]FolderScanner{},
    71→			libs:        map[string]model.Library{},
    72→			status:      map[string]*scanStatus{},
    73→			lock:        &sync.RWMutex{},
    74→			cacheWarmer: cacheWarmer,
    75→		}
    76→		s.loadFolders()
    77→		return s
    78→	})
