			// Setup: Create test audio files
			copyTestAudioFile(testDir, "test.mp3")
			copyTestAudioFile(testDir, "test.flac")

			// Execute: Run full scan
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)

			// Assert: Files should be discovered and imported
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(2)))

			// Verify files are in the database
			allFiles, err := ds.MediaFile(ctx).GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(2))

			// Verify file paths are correct
			filePaths := make(map[string]bool)
			for _, mf := range allFiles {
				filePaths[filepath.Base(mf.Path)] = true
			}
			Expect(filePaths).To(HaveKey("test.mp3"))
			Expect(filePaths).To(HaveKey("test.flac"))
		})

		It("extracts metadata from audio files", func() {
			// Setup: Copy test files with metadata
			copyTestAudioFile(testDir, "test.mp3")

			// Execute: Run scan
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)

			// Assert: Metadata should be extracted
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(int64(0)))

			// Verify metadata fields are populated
			allFiles, err := ds.MediaFile(ctx).GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(1))

			mf := allFiles[0]
			// Metadata like Title, Artist, Album may come from tags or defaults
			Expect(mf.Path).To(ContainSubstring("test.mp3"))
			Expect(mf.Suffix).To(Equal("mp3"))
			// File size and duration should be extracted
			Expect(mf.Size).To(BeGreaterThan(int64(0)))
		})

		It("creates album records from grouped tracks", func() {
			// Setup: Create a subdirectory with multiple tracks (simulating an album)
			albumDir := filepath.Join(testDir, "Test Album")
			Expect(os.MkdirAll(albumDir, os.ModePerm)).To(Succeed())

			copyTestAudioFile(albumDir, "test.mp3")
			copyTestAudioFile(albumDir, "test.flac")

			// Execute: Run scan
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)

			// Assert: Tracks should be imported
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(2)))

			allFiles, err := ds.MediaFile(ctx).GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(2))

			// Verify files have album and artist IDs
			for _, mf := range allFiles {
				Expect(mf.LibraryID).To(Equal(testLibID))
				// Album ID and Artist ID should be set
				Expect(mf.AlbumID).NotTo(BeEmpty())
				Expect(mf.ArtistID).NotTo(BeEmpty())
			}
		})

		It("creates artist records from metadata", func() {
			// Setup: Create audio files
			copyTestAudioFile(testDir, "test.mp3")

			// Execute: Run scan
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)

			// Assert
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(int64(0)))

			// Verify at least one media file exists
			allFiles, err := ds.MediaFile(ctx).GetAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(allFiles).To(HaveLen(GreaterThan(0)))

			// Verify artist information is present
			for _, mf := range allFiles {
				Expect(mf.ArtistID).NotTo(BeEmpty())
				Expect(mf.AlbumArtistID).NotTo(BeEmpty())
			}
		})
	})

	Describe("Incremental Scan", func() {
		It("detects no changes when files haven't been modified", func() {
			// Setup: Run initial scan
			copyTestAudioFile(testDir, "test.mp3")
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(1)))

			// Update library's LastScanAt to current time
			testLib.LastScanAt = time.Now().Add(-1 * time.Second)

			// Execute: Run incremental scan
			progress = make(chan uint32, 100)
			changeCount, err = scanner.Scan(ctx, testLib, false, progress)
			close(progress)

			// Assert: No changes should be detected
			Expect(err).NotTo(HaveOccurred())
			// Since files haven't changed, there should be 0 changes
			// (unchanged files don't count as changes)
			Expect(changeCount).To(Equal(int64(0)))
		})

		It("detects new files in subsequent scans", func() {
			// Setup: Run initial scan with one file
			copyTestAudioFile(testDir, "test.mp3")
			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(1)))

			initialFileCount, err := ds.MediaFile(ctx).CountAll()
			Expect(err).NotTo(HaveOccurred())

			// Update library's LastScanAt
			testLib.LastScanAt = time.Now().Add(-1 * time.Second)

			// Execute: Add new file and scan
			copyTestAudioFile(testDir, "test.flac")
			progress = make(chan uint32, 100)
			changeCount, err = scanner.Scan(ctx, testLib, false, progress)
			close(progress)

			// Assert: New file should be detected
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(BeGreaterThan(int64(0)))

			finalFileCount, err := ds.MediaFile(ctx).CountAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(finalFileCount).To(BeGreaterThan(initialFileCount))
		})
	})

	Describe("File Deletion Detection", func() {
		It("removes database records for deleted files", func() {
			// Setup: Create and scan files
			copyTestAudioFile(testDir, "test.mp3")
			copyTestAudioFile(testDir, "test.flac")

			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(2)))

			initialCount, err := ds.MediaFile(ctx).CountAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(initialCount).To(Equal(int64(2)))

			// Update library's LastScanAt
			testLib.LastScanAt = time.Now().Add(-1 * time.Second)

			// Execute: Delete a file and rescan
			files, _ := os.ReadDir(testDir)
			for _, f := range files {
				if filepath.Ext(f.Name()) == ".flac" {
					_ = os.Remove(filepath.Join(testDir, f.Name()))
				}
			}

			progress = make(chan uint32, 100)
			changeCount, err = scanner.Scan(ctx, testLib, false, progress)
			close(progress)

			// Assert: Deleted file should be removed from DB
			Expect(err).NotTo(HaveOccurred())

			finalCount, err := ds.MediaFile(ctx).CountAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(finalCount).To(Equal(int64(1)))
		})

		It("removes database records for entire deleted folders", func() {
			// Setup: Create folder with files
			albumDir := filepath.Join(testDir, "Album1")
			Expect(os.MkdirAll(albumDir, os.ModePerm)).To(Succeed())

			copyTestAudioFile(albumDir, "test.mp3")
			copyTestAudioFile(albumDir, "test.flac")

			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(2)))

			initialCount, err := ds.MediaFile(ctx).CountAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(initialCount).To(Equal(int64(2)))

			// Update library's LastScanAt
			testLib.LastScanAt = time.Now().Add(-1 * time.Second)

			// Execute: Delete folder and rescan
			_ = os.RemoveAll(albumDir)

			progress = make(chan uint32, 100)
			changeCount, err = scanner.Scan(ctx, testLib, false, progress)
			close(progress)

			// Assert: All folder's files should be removed
			Expect(err).NotTo(HaveOccurred())

			finalCount, err := ds.MediaFile(ctx).CountAll()
			Expect(err).NotTo(HaveOccurred())
			Expect(finalCount).To(Equal(int64(0)))
		})
	})

	Describe("File Update Detection", func() {
		It("updates database records when file modification time changes", func() {
			// Setup: Create and scan file
			testFilePath := filepath.Join(testDir, "test.mp3")
			copyTestAudioFile(testDir, "test.mp3")

			progress := make(chan uint32, 100)
			changeCount, err := scanner.Scan(ctx, testLib, true, progress)
			close(progress)
			Expect(err).NotTo(HaveOccurred())
			Expect(changeCount).To(Equal(int64(1)))

			// Get initial scan time
			files, _ := ds.MediaFile(ctx).GetAll()
			Expect(files).To(HaveLen(1))
			initialUpdatedAt := files[0].UpdatedAt

			// Update library's LastScanAt
			testLib.LastScanAt = time.Now().Add(-2 * time.Second)

			// Execute: Modify file (touch with new time)
			time.Sleep(100 * time.Millisecond)
			f, err := os.OpenFile(testFilePath, os.O_WRONLY, os.ModePerm)
			Expect(err).NotTo(HaveOccurred())
			f.Close()

			os.Chtimes(testFilePath, time.Now(), time.Now())

			progress = make(chan uint32, 100)
			changeCount, err = scanner.Scan(ctx, testLib, false, progress)
			close(progress)

			// Assert: File should be marked as updated
			Expect(err).NotTo(HaveOccurred())

			updatedFiles, _ := ds.MediaFile(ctx).GetAll()
